sql:
SELECT COUNT(test_case_id) AS test_case_count
FROM test_cases
WHERE test_suite_id = 1;

SELECT test_suite_id, COUNT(test_case_id) AS number_of_test_cases
FROM test_cases
GROUP BY test_suite_id;

SELECT test_case_id
FROM test_cases
WHERE status IN ('Passed', 'Failed');

SELECT tc.status, ts.name
FROM test_cases tc
INNER JOIN test_suites ts ON tc.test_suite_id = ts.test_suite_id;

